// Agrupa os dados por sabor e calcula totais + tendência (última semana vs. anterior)
const linhas = items.map(item => item.json);

const semanas = [...new Set(linhas.map(l => l.semana))];
const ultimaSemana = semanas[semanas.length - 1];
const semanaAnterior = semanas[semanas.length - 2];

const sabores = [...new Set(linhas.map(l => l.sabor))];

let resumo = [];
let totalGeral = 0;

for (const sabor of sabores) {
  const linhaAtual = linhas.find(l => l.semana === ultimaSemana && l.sabor === sabor);
  const linhaAnterior = linhas.find(l => l.semana === semanaAnterior && l.sabor === sabor);

  const qtdAtual = linhaAtual ? linhaAtual.quantidade : 0;
  const qtdAnterior = linhaAnterior ? linhaAnterior.quantidade : 0;
  const valorAtual = linhaAtual ? linhaAtual.valor_total : 0;

  const variacao = qtdAnterior > 0
    ? (((qtdAtual - qtdAnterior) / qtdAnterior) * 100).toFixed(1)
    : "N/A";

  totalGeral += valorAtual;

  resumo.push(
    `${sabor}: ${qtdAtual} unidades (R$ ${valorAtual.toFixed(2)}) | variação vs. semana anterior: ${variacao}%`
  );
}

const textoResumo = `Dados da ${ultimaSemana} (Pastelaria Mundial):\n` +
  resumo.join("\n") +
  `\nFaturamento total da semana: R$ ${totalGeral.toFixed(2)}`;

return [{ json: { resumo_dados: textoResumo, faturamento_total: totalGeral } }];

